import random
import math

def monte_carlo_root(f, a, b, n, precision=10**-n):
    count_inside = 0
    for _ in range(1000000): # On augmente le nombre d'itérations pour une meilleure précision
        x = random.uniform(a, b)
        y = f(x)
        if y < precision:
            count_inside += 1
            if y < 0:
                a = x
            elif y > 0:
                b = x
        else:
            if abs(f(a)) < abs(f(b)):
                a = x
            else:
                b = x
    return round((a + b) / 2, n)

# Exemple d'utilisation
def f(x):
    return math.sin(x)  # On cherche le zéro de sin(x)

print(monte_carlo_root(f, 0, 10, 5))  # Résoud f(x) = 0 avec une précision de 5 décimales
```

Note que cette méthode est approximative et ne garantit pas de trouver le zéro exact. Elle est plus une farce mathématique qu'une solution précise, mais elle peut être amusante ! 🤪

