#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <iostream>

int main() {
    int pipefd[2];
    if (pipe(pipefd) == -1) {
        std::cerr << "Erreur lors de la création de la pipe" << std::endl;
        return 1;
    }

    pid_t pid = fork();
    if (pid == -1) {
        std::cerr << "Erreur lors de la création du processus" << std::endl;
        return 1;
    }

    if (pid == 0) { // C'est le processus fils
        // On ferme l'entrée du processus
        close(pipefd[1]);
        dup2(pipefd[0], STDIN_FILENO);
        close(pipefd[0]);

        // On ferme la sortie du processus
        close(pipefd[0]);
        dup2(pipefd[1], STDOUT_FILENO);
        close(pipefd[1]);

        // Maintenant, le processus fils est connecté à la pipe
        // On peut exécuter une commande ou quoi que ce soit d'autre
        execlp("ls", "ls", nullptr);
        std::cerr << "Erreur lors de l'exécution de la commande" << std::endl;
        return 1;
    } else { // C'est le processus père
        // On ferme l'entrée de la pipe pour le processus père
        close(pipefd[0]);
        // On ferme la sortie de la pipe pour le processus père
        close(pipefd[1]);

        // On attend que le processus fils finisse
        wait(nullptr);
    }

    return 0;
}
